const data = $input.first().json.body;

// Datum formatieren
let dateStr = data['your-date'];
try {
  const dateObj = new Date(data['your-date']);
  dateStr = dateObj.toLocaleDateString('de-DE', {
    weekday: 'short',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric'
  });
} catch(e) {
  // Falls Datum nicht parsbar, Rohwert verwenden
}

// WhatsApp-Nachricht zusammenbauen
const message = [
  '\ud83c\udf7d\ufe0f *Neue Reservierungsanfrage*',
  '',
  `\ud83d\udc64 *Name:* ${data['your-name'] || 'k.A.'}`,
  `\ud83d\udcde *Telefon:* ${data['your-phone'] || 'k.A.'}`,
  `\ud83d\udce7 *E-Mail:* ${data['your-email'] || 'k.A.'}`,
  `\ud83d\udcc5 *Datum:* ${dateStr}`,
  `\ud83d\udd50 *Uhrzeit:* ${data['your-time'] || 'k.A.'}`,
  `\ud83d\udc65 *Personen:* ${data['your-guests'] || 'k.A.'}`,
  data['your-message'] ? `\ud83d\udcac *Nachricht:* ${data['your-message']}` : '',
  '',
  `\u23f0 Eingegangen: ${new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' })}`
].filter(l => l !== '').join('\n');

return [{
  json: {
    message,
    customerPhone: data['your-phone'],
    customerName: data['your-name'],
    customerEmail: data['your-email']
  }
}];
